import{_ as o,o as a,c as r,ae as s}from"./chunks/framework.BugOhmHL.js";const m=JSON.parse('{"title":"Componentes de UI","description":"","frontmatter":{},"headers":[],"relativePath":"guia/componentes.md","filePath":"guia/componentes.md"}'),t={name:"guia/componentes.md"};function i(n,e,d,c,l,u){return a(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="componentes-de-ui" tabindex="-1">Componentes de UI <a class="header-anchor" href="#componentes-de-ui" aria-label="Permalink to &quot;Componentes de UI&quot;">​</a></h1><p>A Snapport entrega componentes de interface prontos, responsivos e otimizados. Eles foram desenhados para serem injetados em containers vazios (<code>div</code>) no seu HTML.</p><h2 id="_1-barra-de-busca" tabindex="-1">1. Barra de Busca <a class="header-anchor" href="#_1-barra-de-busca" aria-label="Permalink to &quot;1. Barra de Busca&quot;">​</a></h2><p>Permite filtrar seus projetos instantaneamente através do nome, descrição ou tópicos.</p><ul><li><strong>Comportamento</strong>: A filtragem ocorre em tempo real conforme o usuário digita.</li><li><strong>Identificador</strong>: O input gerado possui o ID <code>#gh-port-search</code> para caso você queira aplicar estilos específicos.</li></ul><h2 id="_2-carrossel-de-filtros" tabindex="-1">2. Carrossel de Filtros <a class="header-anchor" href="#_2-carrossel-de-filtros" aria-label="Permalink to &quot;2. Carrossel de Filtros&quot;">​</a></h2><p>Gera botões dinâmicos baseados nas tecnologias (<code>topics</code>) que a biblioteca encontrou nos seus repositórios.</p><ul><li><strong>Inteligência</strong>: Se você usa <code>react</code> e <code>typescript</code>, a lib gerará botões com os ícones oficiais e cores da marca de cada tecnologia.</li><li><strong>Scroll</strong>: Em dispositivos móveis, o carrossel suporta rolagem horizontal suave com <em>scroll snapping</em>.</li><li><strong>Estado</strong>: O botão &quot;Todos&quot; vem ativado por padrão para exibir a listagem completa.</li></ul><h2 id="_3-cards-de-projeto" tabindex="-1">3. Cards de Projeto <a class="header-anchor" href="#_3-cards-de-projeto" aria-label="Permalink to &quot;3. Cards de Projeto&quot;">​</a></h2><p>Os cards utilizam um layout de proporção <strong>16:9</strong> e possuem uma lógica de fallback para garantir que seu portfólio nunca tenha imagens quebradas.</p><h3 id="gestao-de-imagens-fallback-em-cascata" tabindex="-1">Gestão de Imagens (Fallback em Cascata) <a class="header-anchor" href="#gestao-de-imagens-fallback-em-cascata" aria-label="Permalink to &quot;Gestão de Imagens (Fallback em Cascata)&quot;">​</a></h3><p>A Snapport tenta carregar a imagem seguindo esta ordem de prioridade:</p><ol><li><code>preview.png</code> na raiz do seu repositório.</li><li><strong>GitHub Open Graph</strong>: A imagem gerada pelo GitHub para redes sociais.</li><li><strong>Placeholder</strong>: Um card neutro com o nome do projeto (via <code>placehold.co</code>).</li></ol><h3 id="botoes-de-acao" tabindex="-1">Botões de Ação <a class="header-anchor" href="#botoes-de-acao" aria-label="Permalink to &quot;Botões de Ação&quot;">​</a></h3><ul><li><strong>Github</strong>: Link direto para o código fonte do repositório.</li><li><strong>Acessar</strong>: Este botão é <strong>dinâmico</strong>. Ele só será renderizado se você tiver preenchido o campo <strong>&quot;Homepage&quot;</strong> nas configurações do seu repositório no GitHub.</li></ul><h2 id="_4-skeleton-loading-carregamento" tabindex="-1">4. Skeleton Loading (Carregamento) <a class="header-anchor" href="#_4-skeleton-loading-carregamento" aria-label="Permalink to &quot;4. Skeleton Loading (Carregamento)&quot;">​</a></h2><p>Para evitar que o layout do seu site &quot;pule&quot; enquanto os dados são buscados, a lib exibe <strong>Skeletons</strong> (blocos cinzas com animação de pulsação) que simulam o formato dos cards reais.</p><ul><li><strong>Performance</strong>: Melhora a percepção de velocidade do site e evita mudanças bruscas de layout (<em>Cumulative Layout Shift</em>).</li></ul><hr><h3 id="customizacao-de-layout" tabindex="-1">Customização de Layout <a class="header-anchor" href="#customizacao-de-layout" aria-label="Permalink to &quot;Customização de Layout&quot;">​</a></h3><p>Se você não quiser usar os cards padrão, a Snapport permite injetar o seu próprio HTML através da propriedade <code>customCardTemplate</code> na inicialização da API.</p>',21)])])}const g=o(t,[["render",i]]);export{m as __pageData,g as default};
